import{_ as t,p as o,q as n,a1 as r}from"./framework-7d8e42ec.js";const s={},i=r('<h1 id="项目痛点" tabindex="-1"><a class="header-anchor" href="#项目痛点" aria-hidden="true">#</a> 项目痛点</h1><p>截至 2023-03-27 我个人认为的微应用开发时所产生的困扰如下：</p><ol><li><strong>更新繁琐</strong>：每个微应用仓库都要绑定原始仓库</li><li><strong>更新遗漏</strong>：微应用太多，可能某个微应用会遗漏</li><li><strong>多个仓库</strong>：每个人的 git 仓库一堆，gitlab 目录看着就头疼</li><li><strong>本地多个文件夹</strong>：每个人的电脑上一堆前端微应用文件夹</li><li><strong>占磁盘大</strong>：多个微应用都要安装 node_modules，磁盘占有较大</li><li><strong>开多个编辑器</strong>：开发微应用时，往往会开启多个编辑器，运行多个微应用，占内存高</li><li><strong>核心没有安全隔离</strong>：微应用核心部分和业务部分混合在一起，容易被开发人员改动</li><li><strong>更新冲突</strong>：由于核心隔离较差，导致框架更新时，可能会有一部分冲突</li><li><strong>割席分坐</strong>：一个组里面每个人手里都有一堆微应用，没有整体感</li><li><strong>交接困难</strong>：人员变动后，手里微应用项目可能会有遗漏，溯源困难</li></ol>',3),l=[i];function e(a,g){return o(),n("div",null,l)}const _=t(s,[["render",e],["__file","painSpot.html.vue"]]);export{_ as default};
